#include <print>

template <typename... Args>
constexpr auto second(Args... args) {
    return args...[1];          // 0-based: element #1
}

int main() {
    std::print("{}\n", second(10, 20, 30));
}

#include <print>
#include <type_traits>

template <typename... Ts>
constexpr auto last(Ts... xs) {
    return xs...[sizeof...(Ts) - 1];        // value form
}

template <typename... Ts>
using last_t = Ts...[sizeof...(Ts) - 1];    // type form

int main() {
    static_assert(std::is_same_v<last_t<int, double, char>, char>);
    std::print("{}\n", last(1, 2, 3));
}

#include <print>

template <typename... Ts>
Ts...[0] first_of(Ts... xs) {       // return type is the pack's first type
    return xs...[0];
}

int main() {
    std::print("{}\n", first_of(3.14, 1, 'x'));
}

#include <print>

template <typename... Ts>
constexpr int tweak(Ts... xs) {
    auto& r = xs...[0];      // xs...[0] names the first parameter -> lvalue
    r += 5;                  // mutate through the reference
    return xs...[0];
}

int main() {
    std::print("{}\n", tweak(10, 20, 30));
}

#include <print>

// Only viable if the pack has an index 2 (at least 3 elements)
template <typename... Ts>
auto third(Ts... xs) -> decltype(xs...[2]) {
    return xs...[2];
}

// Fallback for shorter packs
template <typename... Ts>
int third(Ts...) {
    return -1;
}

int main() {
    std::print("{}\n", third(10, 20));
}

