#include <print>
#include <tuple>
#include <mutex>

std::mutex mtx;

std::tuple<int, int, int> stats() { return {1, 2, 3}; }

int main() {
    auto [total, _, count] = stats(); // the middle element isn't needed

    {
        std::lock_guard<std::mutex> _{mtx}; // hold the lock to the end of the block
        std::print("{} / {}\n", total, count);
    }
}

#include <print>
#include <mutex>

std::mutex m1, m2;

void critical() {
    std::lock_guard<std::mutex> _{m1};  // hold m1 to the end of the function
    std::lock_guard<std::mutex> _{m2};  // and m2 -- a different _ variable
    std::print("both locked\n");
}

int main() {
    critical();
}

